   425→        await pool.query(`
   426→          UPDATE parsed_resumes
   427→          SET parsing_status = 'uploaded', parsed_at = NOW()
   428→          WHERE id = $1
   429→        `, [resumeRecord.rows[0].id]);
   430→      }
   431→    } catch (parseErr) {
   432→      console.error('Resume parsing failed (non-fatal):', parseErr.message);
   433→      await pool.query(`
   434→        UPDATE parsed_resumes
   435→        SET parsing_status = 'failed', parsed_at = NOW()
   436→        WHERE id = $1
   437→      `, [resumeRecord.rows[0].id]);
   438→    }
   439→
   440→    res.json({
   441→      success: true,
   442→      resume_url: uploadResult.file.url,
   443→      parsed_data: parsedData,
   444→      resume_id: resumeRecord.rows[0].id
   445→    });
   446→  } catch (err) {
   447→    console.error('Resume upload error:', err);
   448→    res.status(500).json({ error: 'Failed to upload resume' });
   449→  }
   450→});
