    let matchScore = 50;
    try {
      const match = await generateJobMatchScore(candidateProfile, job.rows[0], { subscriptionId });
      matchScore = match.match_score;
    } catch (e) {}

    // Get omniscore for application
    const omniscore = profile.rows[0]?.omniscore || null;

