    const applicationCount = await pool.query(
      'SELECT COUNT(*) as count FROM job_applications WHERE candidate_id = $1',
      [req.user.id]
    );

    const savedJobCount = await pool.query(
      'SELECT COUNT(*) as count FROM saved_jobs WHERE user_id = $1',
      [req.user.id]
    );

