   281→    function applyFilters() {
   282→      const location = document.getElementById('filter-location').value.toLowerCase();
   283→      const type = document.getElementById('filter-type').value;
   284→      const minMatch = parseInt(document.getElementById('filter-match').value) || 0;
   285→
   286→      let filtered = allJobs.filter(job => {
   287→        if (location && job.location && !job.location.toLowerCase().includes(location)) return false;
   288→        if (type && job.job_type !== type) return false;
   289→        if (minMatch && (!job.match || job.match.match_score < minMatch)) return false;
   290→        return true;
   291→      });
   292→
   293→      renderJobs(filtered);
   294→    }
   295→
   296→    function renderJobs(jobs, showMatch = true) {
   297→      const container = document.getElementById('jobs-container');
   298→
   299→      if (!jobs || jobs.length === 0) {
   300→        container.innerHTML = `
   301→          <div class="empty-state">
   302→            <p>No jobs found matching your criteria.</p>
   303→          </div>
   304→        `;
   305→        return;
   306→      }
   307→
   308→      container.innerHTML = `
   309→        <div class="jobs-list">
   310→          ${jobs.map(job => renderJobCard(job, showMatch)).join('')}
   311→        </div>
   312→      `;
   313→    }
   314→
   315→    function renderJobCard(job, showMatch = true) {
   316→      const match = job.match || {};
   317→      const matchScore = match.match_score || 50;
   318→      const matchLevel = match.match_level || 'fair';
   319→      const isSaved = savedJobs.some(s => s.id === job.id);
   320→      const hasApplied = applications.some(a => a.job_id === job.id);
   321→
   322→      return `
   323→        <div class="job-card ${hasApplied ? 'applied' : ''}" onclick="showJobDetail(${job.id})">
   324→          <div class="job-card-main">
   325→            <div class="job-card-header">
   326→              <h3>${job.title}</h3>
   327→              <button class="save-btn ${isSaved ? 'saved' : ''}" onclick="event.stopPropagation(); toggleSave(${job.id})">
   328→                ${isSaved ? '❤️' : '🤍'}
   329→              </button>
   330→            </div>
   331→            <p class="job-company">${job.company || job.posted_by_company || 'Company'}</p>
   332→            <div class="job-meta">
   333→              ${job.location ? `<span class="job-location">📍 ${job.location}</span>` : ''}
   334→              ${job.job_type ? `<span class="job-type">${job.job_type}</span>` : ''}
   335→              ${job.salary_range ? `<span class="job-salary">💰 ${job.salary_range}</span>` : ''}
   336→            </div>
   337→          </div>
   338→          ${showMatch ? `
   339→            <div class="job-card-match">
   340→              <div class="match-indicator ${matchLevel}">
   341→                <span class="match-percent">${matchScore}%</span>
   342→                <span class="match-label">match</span>
   343→              </div>
   344→              ${hasApplied ? '<span class="applied-badge">Applied</span>' : ''}
   345→            </div>
   346→          ` : ''}
   347→        </div>
   348→      `;
   349→    }
   350→
   351→    function renderSavedJobs() {
   352→      const container = document.getElementById('jobs-container');
   353→
   354→      if (savedJobs.length === 0) {
   355→        container.innerHTML = `
   356→          <div class="empty-state">
   357→            <h3>No Saved Jobs</h3>
   358→            <p>Save jobs you're interested in to apply later.</p>
   359→            <button class="btn btn-primary" onclick="switchTab('recommended')">Browse Jobs</button>
   360→          </div>
   361→        `;
   362→        return;
   363→      }
   364→
   365→      container.innerHTML = `
   366→        <div class="jobs-list">
   367→          ${savedJobs.map(job => renderJobCard(job, true)).join('')}
   368→        </div>
   369→      `;
   370→    }
   371→
   372→    function renderApplications() {
   373→      const container = document.getElementById('jobs-container');
   374→
   375→      if (applications.length === 0) {
   376→        container.innerHTML = `
   377→          <div class="empty-state">
   378→            <h3>No Applications Yet</h3>
   379→            <p>Apply to jobs to track your applications here.</p>
   380→            <button class="btn btn-primary" onclick="switchTab('recommended')">Find Jobs</button>
   381→          </div>
   382→        `;
   383→        return;
   384→      }
   385→
   386→      container.innerHTML = `
   387→        <div class="applications-list">
   388→          ${applications.map(app => `
   389→            <div class="application-card" onclick="showJobDetail(${app.job_id})">
   390→              <div class="application-info">
   391→                <h4>${app.title}</h4>
   392→                <p>${app.company || app.posted_by_company || 'Company'}</p>
   393→                <span class="application-date">Applied ${formatDate(app.applied_at)}</span>
   394→              </div>
   395→              <div class="application-status">
   396→                <span class="status-badge ${app.status}">${formatStatus(app.status)}</span>
   397→                ${app.match_score ? `<span class="match-score">${app.match_score}% match</span>` : ''}
   398→              </div>
   399→            </div>
   400→          `).join('')}
   401→        </div>
   402→      `;
   403→    }
   404→
   405→    function formatDate(dateStr) {
   406→      const date = new Date(dateStr);
   407→      return date.toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' });
   408→    }
   409→
   410→    function formatStatus(status) {
   411→      const labels = {
   412→        'applied': 'Applied',
   413→        'reviewing': 'Under Review',
   414→        'interviewing': 'Interviewing',
   415→        'offered': 'Offer Received',
   416→        'rejected': 'Not Selected',
   417→        'accepted': 'Accepted'
   418→      };
   419→      return labels[status] || status;
   420→    }
   421→
   422→    async function showJobDetail(jobId) {
   423→      selectedJobId = jobId;
   424→      const job = allJobs.find(j => j.id === jobId) ||
   425→                  savedJobs.find(j => j.id === jobId) ||
   426→                  applications.find(a => a.job_id === jobId);
   427→
   428→      if (!job) return;
   429→
   430→      const match = job.match || {};
   431→      const isSaved = savedJobs.some(s => s.id === jobId);
   432→      const hasApplied = applications.some(a => a.job_id === jobId);
   433→
   434→      const panel = document.getElementById('job-detail-panel');
   435→      const content = document.getElementById('job-detail-content');
   436→
   437→      content.innerHTML = `
   438→        <button class="close-panel-btn" onclick="closeDetailPanel()">×</button>
   439→
   440→        <div class="job-detail-header">
   441→          <h2>${job.title}</h2>
