   512→    async function toggleSave(jobId) {
   513→      const isSaved = savedJobs.some(s => s.id === jobId);
   514→
   515→      try {
   516→        if (isSaved) {
   517→          await apiCall(`/candidate/jobs/${jobId}/save`, { method: 'DELETE' });
   518→          savedJobs = savedJobs.filter(s => s.id !== jobId);
   519→        } else {
   520→          await apiCall(`/candidate/jobs/${jobId}/save`, { method: 'POST' });
   521→          const job = allJobs.find(j => j.id === jobId);
   522→          if (job) savedJobs.push(job);
   523→        }
   524→
   525→        document.getElementById('saved-count').textContent = savedJobs.length;
   526→
   527→        // Re-render current view
   528→        if (currentTab === 'saved') {
   529→          renderSavedJobs();
   530→        } else {
   531→          renderJobs(allJobs);
   532→        }
   533→
   534→        // Update detail panel if open
   535→        if (selectedJobId === jobId) {
   536→          showJobDetail(jobId);
   537→        }
   538→      } catch (err) {
   539→        console.error('Toggle save error:', err);
   540→      }
   541→    }
