    }

    function applyFilters() {
      const location = document.getElementById('filter-location').value.toLowerCase();
      const type = document.getElementById('filter-type').value;
      const minMatch = parseInt(document.getElementById('filter-match').value) || 0;

      let filtered = allJobs.filter(job => {
        if (location && job.location && !job.location.toLowerCase().includes(location)) return false;
        if (type && job.job_type !== type) return false;
        if (minMatch && (!job.match || job.match.match_score < minMatch)) return false;
        return true;
      });

      renderJobs(filtered);
    }

    function renderJobs(jobs, showMatch = true) {
      const container = document.getElementById('jobs-container');

      if (!jobs || jobs.length === 0) {
        container.innerHTML = `
          <div class="empty-state">
            <p>No jobs found matching your criteria.</p>
          </div>
        `;
        return;
      }

      container.innerHTML = `
        <div class="jobs-list">
          ${jobs.map(job => renderJobCard(job, showMatch)).join('')}
        </div>
      `;
    }

    function renderJobCard(job, showMatch = true) {
      const match = job.match || {};
      const matchScore = match.match_score || 50;
      const matchLevel = match.match_level || 'fair';
      const isSaved = savedJobs.some(s => s.id === job.id);
      const hasApplied = applications.some(a => a.job_id === job.id);

      return `
        <div class="job-card ${hasApplied ? 'applied' : ''}" onclick="showJobDetail(${job.id})">
          <div class="job-card-main">
            <div class="job-card-header">
              <h3>${job.title}</h3>
              <button class="save-btn ${isSaved ? 'saved' : ''}" onclick="event.stopPropagation(); toggleSave(${job.id})">
                ${isSaved ? '❤️' : '🤍'}
              </button>
            </div>
            <p class="job-company">${job.company || job.posted_by_company || 'Company'}</p>
            <div class="job-meta">
              ${job.location ? `<span class="job-location">📍 ${job.location}</span>` : ''}
              ${job.job_type ? `<span class="job-type">${job.job_type}</span>` : ''}
              ${job.salary_range ? `<span class="job-salary">💰 ${job.salary_range}</span>` : ''}
            </div>
          </div>
          ${showMatch ? `
            <div class="job-card-match">
              <div class="match-indicator ${matchLevel}">
                <span class="match-percent">${matchScore}%</span>
                <span class="match-label">match</span>
              </div>
              ${hasApplied ? '<span class="applied-badge">Applied</span>' : ''}
            </div>
          ` : ''}
        </div>
      `;
    }

    function renderSavedJobs() {
      const container = document.getElementById('jobs-container');

      if (savedJobs.length === 0) {
        container.innerHTML = `
          <div class="empty-state">
            <h3>No Saved Jobs</h3>
            <p>Save jobs you're interested in to apply later.</p>
            <button class="btn btn-primary" onclick="switchTab('recommended')">Browse Jobs</button>
          </div>
        `;
        return;
      }

      container.innerHTML = `
        <div class="jobs-list">
          ${savedJobs.map(job => renderJobCard(job, true)).join('')}
        </div>
      `;
    }

    function renderApplications() {
      const container = document.getElementById('jobs-container');

      if (applications.length === 0) {
        container.innerHTML = `
          <div class="empty-state">
            <h3>No Applications Yet</h3>
            <p>Apply to jobs to track your applications here.</p>
            <button class="btn btn-primary" onclick="switchTab('recommended')">Find Jobs</button>
          </div>
        `;
        return;
      }

      container.innerHTML = `
        <div class="applications-list">
          ${applications.map(app => `
            <div class="application-card" onclick="showJobDetail(${app.job_id})">
              <div class="application-info">
                <h4>${app.title}</h4>
                <p>${app.company || app.posted_by_company || 'Company'}</p>
                <span class="application-date">Applied ${formatDate(app.applied_at)}</span>
              </div>
              <div class="application-status">
                <span class="status-badge ${app.status}">${formatStatus(app.status)}</span>
                ${app.match_score ? `<span class="match-score">${app.match_score}% match</span>` : ''}
              </div>
            </div>
          `).join('')}
        </div>
      `;
    }

    function formatDate(dateStr) {
      const date = new Date(dateStr);
      return date.toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' });
    }

    function formatStatus(status) {
      const labels = {
        'applied': 'Applied',
        'reviewing': 'Under Review',
        'interviewing': 'Interviewing',
        'offered': 'Offer Received',
        'rejected': 'Not Selected',
        'accepted': 'Accepted'
      };
      return labels[status] || status;
    }

    async function showJobDetail(jobId) {
      selectedJobId = jobId;
      const job = allJobs.find(j => j.id === jobId) ||
                  savedJobs.find(j => j.id === jobId) ||
                  applications.find(a => a.job_id === jobId);

      if (!job) return;

      const match = job.match || {};
      const isSaved = savedJobs.some(s => s.id === jobId);
      const hasApplied = applications.some(a => a.job_id === jobId);

      const panel = document.getElementById('job-detail-panel');
      const content = document.getElementById('job-detail-content');

      content.innerHTML = `
        <button class="close-panel-btn" onclick="closeDetailPanel()">×</button>

        <div class="job-detail-header">
          <h2>${job.title}</h2>
          <p class="detail-company">${job.company || job.posted_by_company || 'Company'}</p>
        </div>

        <div class="job-detail-meta">
          ${job.location ? `<span>📍 ${job.location}</span>` : ''}
          ${job.job_type ? `<span>⏰ ${job.job_type}</span>` : ''}
          ${job.salary_range ? `<span>💰 ${job.salary_range}</span>` : ''}
        </div>

        ${match.match_score ? `
          <div class="job-match-card ${match.match_level}">
            <div class="match-header">
              <span class="match-big-score">${match.match_score}%</span>
              <span class="match-big-label">${match.match_level} match</span>
            </div>
            ${match.recommendation ? `<p class="match-recommendation">${match.recommendation}</p>` : ''}
            ${match.matching_skills && match.matching_skills.length > 0 ? `
              <div class="match-skills">
                <strong>Matching Skills:</strong>
                <div class="skill-chips">
                  ${match.matching_skills.map(s => `<span class="skill-chip match">${s}</span>`).join('')}
                </div>
              </div>
            ` : ''}
            ${match.missing_skills && match.missing_skills.length > 0 ? `
              <div class="match-skills">
                <strong>Skills to Develop:</strong>
                <div class="skill-chips">
                  ${match.missing_skills.map(s => `<span class="skill-chip missing">${s}</span>`).join('')}
                </div>
              </div>
            ` : ''}
          </div>
        ` : ''}

        <div class="job-detail-section">
          <h3>Description</h3>
          <div class="job-description">${job.description || 'No description provided.'}</div>
        </div>

        ${job.requirements ? `
          <div class="job-detail-section">
            <h3>Requirements</h3>
            <div class="job-requirements">${job.requirements}</div>
          </div>
        ` : ''}

        <div class="job-detail-actions">
          <button class="btn btn-ghost" onclick="toggleSave(${jobId})">
            ${isSaved ? '❤️ Saved' : '🤍 Save'}
          </button>
          ${hasApplied ? `
            <button class="btn btn-primary" disabled>Applied ✓</button>
          ` : `
            <button class="btn btn-primary" onclick="showApplyModal(${jobId})">Apply Now</button>
          `}
        </div>

        <div class="job-detail-footer">
          <span>Posted ${formatDate(job.created_at)}</span>
        </div>
      `;

      panel.classList.add('active');
    }

    function closeDetailPanel() {
      document.getElementById('job-detail-panel').classList.remove('active');
    }

    async function toggleSave(jobId) {
      const isSaved = savedJobs.some(s => s.id === jobId);

      try {
        if (isSaved) {
          await apiCall(`/candidate/jobs/${jobId}/save`, { method: 'DELETE' });
          savedJobs = savedJobs.filter(s => s.id !== jobId);
        } else {
          await apiCall(`/candidate/jobs/${jobId}/save`, { method: 'POST' });
          const job = allJobs.find(j => j.id === jobId);
          if (job) savedJobs.push(job);
        }

        document.getElementById('saved-count').textContent = savedJobs.length;

        // Re-render current view
        if (currentTab === 'saved') {
          renderSavedJobs();
        } else {
          renderJobs(allJobs);
        }

        // Update detail panel if open
        if (selectedJobId === jobId) {
          showJobDetail(jobId);
        }
      } catch (err) {
        console.error('Toggle save error:', err);
      }
    }

    function showApplyModal(jobId) {
      selectedJobId = jobId;
      const job = allJobs.find(j => j.id === jobId) || savedJobs.find(j => j.id === jobId);

      if (!job) return;

      const match = job.match || {};

      document.getElementById('apply-job-title').textContent = job.title;
      document.getElementById('apply-match-score').textContent = (match.match_score || 50) + '%';
      document.getElementById('apply-match-level').textContent =
        (match.match_level || 'fair').charAt(0).toUpperCase() + (match.match_level || 'fair').slice(1) + ' Match';
      document.getElementById('apply-match-desc').textContent = 'Based on your skills and OmniScore';

      const circle = document.getElementById('apply-match-circle');
      circle.className = 'match-circle ' + (match.match_level || 'fair');

      document.getElementById('cover-letter').value = '';

      // Render screening questions
      const sqArea = document.getElementById('screening-questions-area');
      const sqForm = document.getElementById('screening-questions-form');
      const questions = job.screening_questions || [];

      if (questions.length > 0) {
        sqArea.style.display = 'block';
        sqForm.innerHTML = questions.map(q => {
          const reqTag = q.required ? '<span style="color: #ef4444;">*</span>' : '';
          let inputHTML = '';

          if (q.type === 'yes_no') {
            inputHTML = `
              <div class="sq-answer-options">
                <label class="sq-radio"><input type="radio" name="sq_${q.id}" value="yes" ${q.required ? 'required' : ''}> Yes</label>
                <label class="sq-radio"><input type="radio" name="sq_${q.id}" value="no"> No</label>
              </div>`;
          } else if (q.type === 'select') {
            inputHTML = `<select class="sq-input" id="sq_${q.id}" ${q.required ? 'required' : ''}>
              <option value="">Select...</option>
              ${(q.options || []).map(o => `<option value="${o}">${o}</option>`).join('')}
            </select>`;
          } else if (q.type === 'number') {
            inputHTML = `<input type="number" class="sq-input" id="sq_${q.id}" placeholder="${q.placeholder || ''}" ${q.required ? 'required' : ''}>`;
          } else {
            inputHTML = `<input type="text" class="sq-input" id="sq_${q.id}" placeholder="${q.placeholder || 'Your answer...'}" ${q.required ? 'required' : ''}>`;
          }

          return `
            <div class="sq-field" style="margin-bottom: 16px;">
              <label style="font-size: 14px; font-weight: 500; display: block; margin-bottom: 6px;">${q.question} ${reqTag}</label>
              ${inputHTML}
            </div>`;
        }).join('');
      } else {
        sqArea.style.display = 'none';
        sqForm.innerHTML = '';
      }

      showModal();
    }

    function showModal() {
      document.getElementById('modal-overlay').classList.add('active');
      document.getElementById('apply-modal').classList.add('active');
    }

    function closeModal() {
      document.getElementById('modal-overlay').classList.remove('active');
      document.getElementById('apply-modal').classList.remove('active');
    }

    async function submitApplication() {
      const coverLetter = document.getElementById('cover-letter').value;
      const btn = document.getElementById('submit-apply-btn');

      // Collect screening answers
      const job = allJobs.find(j => j.id === selectedJobId) || savedJobs.find(j => j.id === selectedJobId);
      const questions = (job && job.screening_questions) || [];
      const screening_answers = {};

      for (const q of questions) {
        let val;
        if (q.type === 'yes_no') {
          const checked = document.querySelector(`input[name="sq_${q.id}"]:checked`);
          val = checked ? checked.value : '';
        } else {
          const el = document.getElementById(`sq_${q.id}`);
          val = el ? el.value.trim() : '';
        }

        if (q.required && !val) {
          alert(`Please answer: "${q.question}"`);
          return;
        }
        screening_answers[q.id] = val;
      }

      btn.textContent = 'Submitting...';
      btn.disabled = true;

      try {
        const data = await apiCall(`/candidate/jobs/${selectedJobId}/apply`, {
          method: 'POST',
          body: JSON.stringify({ cover_letter: coverLetter, screening_answers })
        });

        if (data.success) {
          closeModal();
          applications.push(data.application);
          document.getElementById('applied-count').textContent = applications.length;

          // Re-render and show success
          if (currentTab === 'recommended' || currentTab === 'all') {
            renderJobs(allJobs);
          }

          // Update detail panel
          showJobDetail(selectedJobId);

          alert('Application submitted successfully! 🎉');
        }
      } catch (err) {
        console.error('Apply error:', err);
        alert('Failed to submit application. Please try again.');
      } finally {
        btn.textContent = 'Submit Application';
        btn.disabled = false;
      }
    }
  </script>

