      display: flex;
      gap: 16px;
      margin-bottom: 24px;
      padding: 16px;
      background: var(--bg-card);
      border: 1px solid var(--border-color);
      border-radius: var(--radius-md);
    }

    .filter-group {
      display: flex;
      flex-direction: column;
      gap: 6px;
    }

    .filter-group label {
      font-size: 12px;
      color: var(--text-muted);
    }

    .filter-group select {
      padding: 8px 12px;
      background: var(--bg-elevated);
      border: 1px solid var(--border-color);
      border-radius: var(--radius-md);
      color: var(--text-primary);
      font-size: 13px;
      min-width: 150px;
    }

    .jobs-list {
      display: flex;
      flex-direction: column;
      gap: 16px;
    }

    .job-card {
      display: flex;
      justify-content: space-between;
      align-items: center;
      padding: 20px 24px;
      background: var(--bg-card);
      border: 1px solid var(--border-color);
      border-radius: var(--radius-lg);
      cursor: pointer;
      transition: all 0.2s;
    }

    .job-card:hover {
      border-color: var(--accent-primary);
      transform: translateX(4px);
    }

    .job-card.applied {
      border-left: 3px solid var(--accent-primary);
    }

    .job-card-header {
      display: flex;
      align-items: flex-start;
      gap: 12px;
    }

    .job-card-header h3 {
      font-family: var(--font-display);
      font-size: 18px;
      margin-bottom: 4px;
    }

    .save-btn {
      background: none;
      border: none;
      font-size: 20px;
      cursor: pointer;
      opacity: 0.5;
      transition: all 0.2s;
    }

    .save-btn:hover, .save-btn.saved {
      opacity: 1;
    }

    .job-company {
      color: var(--text-secondary);
      font-size: 14px;
      margin-bottom: 12px;
    }

    .job-meta {
      display: flex;
      gap: 16px;
      font-size: 13px;
      color: var(--text-muted);
    }

    .job-type {
      padding: 4px 8px;
      background: var(--bg-elevated);
      border-radius: var(--radius-full);
      text-transform: capitalize;
    }

    .job-card-match {
      display: flex;
      flex-direction: column;
      align-items: flex-end;
      gap: 8px;
    }

    .match-indicator {
      display: flex;
      flex-direction: column;
      align-items: center;
      padding: 12px 16px;
      border-radius: var(--radius-md);
      min-width: 80px;
    }

    .match-indicator.excellent {
      background: rgba(16, 185, 129, 0.2);
      color: var(--accent-primary);
    }

    .match-indicator.good {
      background: rgba(16, 185, 129, 0.15);
      color: var(--accent-primary);
    }

    .match-indicator.fair {
      background: rgba(245, 158, 11, 0.15);
      color: #f59e0b;
    }

    .match-indicator.poor {
      background: rgba(239, 68, 68, 0.15);
      color: #ef4444;
    }

    .match-percent {
      font-family: var(--font-display);
      font-size: 24px;
      font-weight: 700;
    }

    .match-label {
      font-size: 11px;
      opacity: 0.8;
    }

    .applied-badge {
      padding: 4px 12px;
      background: var(--accent-primary);
      color: #000;
      border-radius: var(--radius-full);
      font-size: 12px;
      font-weight: 600;
    }

    /* Applications list */
    .applications-list {
      display: flex;
      flex-direction: column;
      gap: 12px;
    }

    .application-card {
      display: flex;
      justify-content: space-between;
      align-items: center;
      padding: 20px 24px;
      background: var(--bg-card);
      border: 1px solid var(--border-color);
      border-radius: var(--radius-lg);
      cursor: pointer;
      transition: all 0.2s;
    }

    .application-card:hover {
      border-color: var(--accent-primary);
    }

    .application-info h4 {
      font-family: var(--font-display);
      font-size: 16px;
      margin-bottom: 4px;
    }

    .application-info p {
      color: var(--text-secondary);
      font-size: 14px;
      margin-bottom: 8px;
    }

    .application-date {
      font-size: 12px;
      color: var(--text-muted);
    }

    .application-status {
      display: flex;
      flex-direction: column;
      align-items: flex-end;
      gap: 8px;
    }

    .status-badge {
      padding: 6px 12px;
      border-radius: var(--radius-full);
      font-size: 12px;
      font-weight: 600;
    }

    .status-badge.applied {
      background: rgba(59, 130, 246, 0.2);
      color: #3b82f6;
    }

    .status-badge.reviewing {
      background: rgba(245, 158, 11, 0.2);
      color: #f59e0b;
    }

    .status-badge.interviewing {
      background: rgba(16, 185, 129, 0.2);
      color: var(--accent-primary);
    }

    .status-badge.offered {
      background: var(--accent-primary);
      color: #000;
    }

    .status-badge.rejected {
      background: rgba(239, 68, 68, 0.2);
      color: #ef4444;
    }

    .match-score {
      font-size: 13px;
      color: var(--text-muted);
    }

    /* Job Detail Panel */
    .job-detail-panel {
      position: fixed;
      top: 0;
      right: 0;
      width: 500px;
      height: 100vh;
      background: var(--bg-secondary);
      border-left: 1px solid var(--border-color);
      transform: translateX(100%);
      transition: transform 0.3s ease;
      overflow-y: auto;
      z-index: 50;
    }

    .job-detail-panel.active {
      transform: translateX(0);
    }

    .job-detail-content {
      padding: 32px;
    }

    .close-panel-btn {
      position: absolute;
      top: 16px;
      right: 16px;
      background: var(--bg-elevated);
      border: none;
      width: 32px;
      height: 32px;
      border-radius: 50%;
      font-size: 20px;
      color: var(--text-muted);
      cursor: pointer;
    }

    .job-detail-header h2 {
      font-family: var(--font-display);
      font-size: 24px;
      margin-bottom: 8px;
    }

    .detail-company {
      color: var(--text-secondary);
      font-size: 16px;
      margin-bottom: 16px;
    }

    .job-detail-meta {
      display: flex;
      flex-wrap: wrap;
      gap: 12px;
      margin-bottom: 24px;
      font-size: 14px;
      color: var(--text-muted);
    }

    .job-match-card {
      padding: 20px;
      border-radius: var(--radius-lg);
      margin-bottom: 24px;
    }

    .job-match-card.excellent {
      background: rgba(16, 185, 129, 0.15);
      border: 1px solid rgba(16, 185, 129, 0.3);
    }

    .job-match-card.good {
      background: rgba(16, 185, 129, 0.1);
      border: 1px solid rgba(16, 185, 129, 0.2);
    }

    .job-match-card.fair {
      background: rgba(245, 158, 11, 0.1);
      border: 1px solid rgba(245, 158, 11, 0.2);
    }

    .job-match-card.poor {
      background: rgba(239, 68, 68, 0.1);
      border: 1px solid rgba(239, 68, 68, 0.2);
    }

    .match-header {
      display: flex;
      align-items: baseline;
      gap: 8px;
      margin-bottom: 12px;
    }

    .match-big-score {
      font-family: var(--font-display);
      font-size: 36px;
      font-weight: 700;
    }

    .job-match-card.excellent .match-big-score,
    .job-match-card.good .match-big-score {
      color: var(--accent-primary);
    }

    .job-match-card.fair .match-big-score {
      color: #f59e0b;
    }

    .job-match-card.poor .match-big-score {
      color: #ef4444;
    }

    .match-big-label {
      font-size: 14px;
      color: var(--text-secondary);
      text-transform: capitalize;
    }

    .match-recommendation {
      font-size: 14px;
      color: var(--text-secondary);
      margin-bottom: 16px;
    }

    .match-skills {
      margin-bottom: 12px;
    }

    .match-skills strong {
      display: block;
      font-size: 12px;
      color: var(--text-muted);
      margin-bottom: 8px;
    }

    .skill-chips {
      display: flex;
      flex-wrap: wrap;
      gap: 6px;
    }

    .skill-chip {
      padding: 4px 10px;
      border-radius: var(--radius-full);
      font-size: 12px;
    }

    .skill-chip.match {
      background: rgba(16, 185, 129, 0.2);
      color: var(--accent-primary);
    }

    .skill-chip.missing {
      background: rgba(239, 68, 68, 0.1);
      color: #ef4444;
    }

    .job-detail-section {
      margin-bottom: 24px;
    }

    .job-detail-section h3 {
      font-family: var(--font-display);
      font-size: 16px;
      margin-bottom: 12px;
    }

    .job-description, .job-requirements {
      font-size: 14px;
      color: var(--text-secondary);
      line-height: 1.7;
      white-space: pre-wrap;
    }

    .job-detail-actions {
      display: flex;
      gap: 12px;
      margin-bottom: 24px;
    }

    .job-detail-footer {
      font-size: 12px;
      color: var(--text-muted);
      padding-top: 16px;
      border-top: 1px solid var(--border-color);
    }

    /* Screening Question Inputs */
    .sq-input {
      width: 100%;
      padding: 10px 14px;
      background: var(--bg-elevated);
      border: 1px solid var(--border-color);
      border-radius: var(--radius-md);
      color: var(--text-primary);
      font-size: 14px;
    }
    .sq-input:focus { outline: none; border-color: var(--accent-primary); }
    .sq-answer-options { display: flex; gap: 20px; margin-top: 4px; }
    .sq-radio { display: flex; align-items: center; gap: 6px; font-size: 14px; cursor: pointer; }
    .sq-radio input { width: 16px; height: 16px; }

    /* Apply Modal */
    .modal-overlay {
      position: fixed;
      top: 0;
      left: 0;
      right: 0;
      bottom: 0;
      background: rgba(0, 0, 0, 0.7);
      z-index: 100;
      display: none;
    }

    .modal-overlay.active {
      display: block;
    }

    .modal {
      position: fixed;
      top: 50%;
      left: 50%;
      transform: translate(-50%, -50%);
      background: var(--bg-card);
      border: 1px solid var(--border-color);
      border-radius: var(--radius-lg);
      width: 90%;
      max-width: 500px;
      max-height: 90vh;
      overflow-y: auto;
      z-index: 101;
      display: none;
    }

    .modal.active {
      display: block;
    }

    .modal-header {
      display: flex;
      justify-content: space-between;
      align-items: center;
      padding: 20px 24px;
      border-bottom: 1px solid var(--border-color);
    }

    .modal-header h3 {
      font-family: var(--font-display);
      font-size: 18px;
    }

    .modal-close {
      background: none;
      border: none;
      font-size: 24px;
      color: var(--text-muted);
      cursor: pointer;
    }

    .modal-body {
      padding: 24px;
    }

    .modal-footer {
      display: flex;
      justify-content: flex-end;
      gap: 12px;
      padding: 20px 24px;
      border-top: 1px solid var(--border-color);
    }

    .apply-match-preview {
      display: flex;
      align-items: center;
      gap: 20px;
      padding: 20px;
      background: var(--bg-elevated);
      border-radius: var(--radius-lg);
      margin-bottom: 20px;
    }

    .match-circle {
      width: 70px;
      height: 70px;
      border-radius: 50%;
      display: flex;
      align-items: center;
      justify-content: center;
      font-family: var(--font-display);
      font-size: 20px;
      font-weight: 700;
    }

    .match-circle.excellent, .match-circle.good {
      background: rgba(16, 185, 129, 0.2);
      color: var(--accent-primary);
    }

    .match-circle.fair {
      background: rgba(245, 158, 11, 0.2);
      color: #f59e0b;
    }

    .match-info {
      display: flex;
      flex-direction: column;
      gap: 4px;
    }

    .match-info .match-level {
      font-weight: 600;
    }

    .match-info .match-desc {
      font-size: 13px;
      color: var(--text-muted);
    }

    .form-group {
      margin-bottom: 20px;
    }

    .form-group label {
      display: block;
      font-size: 13px;
      font-weight: 500;
      margin-bottom: 8px;
    }

    .form-group textarea {
      width: 100%;
      padding: 12px;
      background: var(--bg-elevated);
      border: 1px solid var(--border-color);
      border-radius: var(--radius-md);
      color: var(--text-primary);
      font-size: 14px;
      resize: vertical;
    }

    .form-group textarea:focus {
      outline: none;
      border-color: var(--accent-primary);
    }

    .apply-checklist {
      padding: 16px;
      background: var(--bg-elevated);
      border-radius: var(--radius-md);
    }

    .apply-checklist h4 {
      font-size: 14px;
      margin-bottom: 12px;
    }

    .apply-checklist ul {
      list-style: none;
    }

    .apply-checklist li {
      display: flex;
      align-items: center;
      gap: 8px;
      padding: 6px 0;
      font-size: 13px;
      color: var(--text-secondary);
    }

    .apply-checklist .check {
      color: var(--accent-primary);
    }

    @media (max-width: 1024px) {
      .job-detail-panel {
        width: 100%;
      }
    }

    @media (max-width: 768px) {
      .job-tabs {
        flex-wrap: wrap;
      }

      .job-filters {
        flex-direction: column;
      }

      .job-card {
        flex-direction: column;
        align-items: flex-start;
        gap: 16px;
      }

      .job-card-match {
        flex-direction: row;
        width: 100%;
        justify-content: space-between;
      }
    }
  </style>
</body>
</html>

