   182→          </div>
   183→          <div class="form-group">
   184→            <label for="offer-start-date">Start Date</label>
   185→            <input type="date" id="offer-start-date" required>
   186→          </div>
   187→        </div>
   188→        <div class="form-group">
   189→          <label for="offer-benefits">Benefits Package</label>
   190→          <textarea id="offer-benefits" rows="3" placeholder="Health insurance, 401(k) matching, PTO, etc."></textarea>
   191→        </div>
   192→        <div class="form-actions">
   193→          <button type="button" onclick="closeOfferModal()" class="btn btn-ghost">Cancel</button>
   194→          <button type="submit" class="btn btn-primary">Send Offer</button>
   195→        </div>
   196→      </form>
   197→    </div>
   198→  </div>
   199→
   200→  <script src="/js/main.js"></script>
   201→  <script>
   202→    let currentFilter = 'all';
   203→    let currentJob = '';
   204→    let applications = [];
   205→
   206→    document.addEventListener('DOMContentLoaded', async () => {
   207→      const user = await checkAuth();
   208→      if (!user) {
   209→        window.location.href = '/login.html';
   210→        return;
   211→      }
   212→      // Verify recruiter/employer role - must have company_id and appropriate role
   213→      const allowedRoles = ['employer', 'recruiter', 'hiring_manager', 'admin'];
   214→      if (!user.company_id || !allowedRoles.includes(user.role)) {
   215→        window.location.href = '/candidate-dashboard.html';
   216→        return;
   217→      }
   218→
   219→      const name = user.name || user.email.split('@')[0];
   220→      document.getElementById('user-name').textContent = name;
   221→      document.getElementById('user-avatar').textContent = name.charAt(0).toUpperCase();
   222→      document.getElementById('company-name').textContent = user.company_name || 'Company';
   223→      document.getElementById('dropdown-user-name').textContent = name;
   224→      document.getElementById('dropdown-user-email').textContent = user.email;
   225→
   226→      // Setup user menu dropdown
   227→      const userMenuToggle = document.getElementById('user-menu-toggle');
   228→      const userDropdownMenu = document.getElementById('user-dropdown-menu');
   229→      if (userMenuToggle && userDropdownMenu) {
   230→        userMenuToggle.addEventListener('click', (e) => {
   231→          e.stopPropagation();
   232→          userDropdownMenu.classList.toggle('active');
   233→        });
   234→        document.addEventListener('click', () => {
   235→          userDropdownMenu.classList.remove('active');
   236→        });
   237→      }
   238→
   239→      // Setup filter tabs
   240→      document.querySelectorAll('.filter-tab').forEach(tab => {
   241→        tab.addEventListener('click', () => {
   242→          document.querySelectorAll('.filter-tab').forEach(t => t.classList.remove('active'));
   243→          tab.classList.add('active');
   244→          currentFilter = tab.dataset.status;
   245→          renderApplications();
   246→        });
   247→      });
   248→
   249→      // Setup job filter
   250→      document.getElementById('job-filter').addEventListener('change', (e) => {
   251→        currentJob = e.target.value;
   252→        renderApplications();
   253→      });
   254→
   255→      loadJobs();
   256→      loadApplications();
   257→    });
   258→
   259→    async function loadJobs() {
   260→      try {
   261→        const data = await apiCall('/recruiter/jobs');
   262→        if (data.jobs) {
   263→          const select = document.getElementById('job-filter');
   264→          data.jobs.forEach(job => {
   265→            const option = document.createElement('option');
   266→            option.value = job.id;
   267→            option.textContent = job.title;
   268→            select.appendChild(option);
   269→          });
   270→        }
   271→      } catch (err) {
   272→        console.error('Failed to load jobs:', err);
   273→      }
   274→    }
   275→
   276→    async function loadApplications() {
   277→      try {
   278→        const data = await apiCall('/recruiter/applications');
   279→        if (data.applications) {
   280→          applications = data.applications;
   281→          updateStats(applications);
   282→          renderApplications();
   283→        }
   284→      } catch (err) {
   285→        console.error('Failed to load applications:', err);
   286→        document.getElementById('applications-list').innerHTML = `
   287→          <div class="empty-state">
   288→            <p>Failed to load applications</p>
   289→          </div>
   290→        `;
   291→      }
   292→    }
   293→
   294→    function updateStats(apps) {
   295→      document.getElementById('total-applications').textContent = apps.length;
   296→
   297→      const today = new Date().toDateString();
   298→      const newToday = apps.filter(a => new Date(a.applied_at).toDateString() === today).length;
   299→      document.getElementById('new-applications').textContent = newToday;
   300→
   301→      document.getElementById('reviewing-count').textContent =
   302→        apps.filter(a => a.status === 'reviewing').length;
   303→      document.getElementById('offered-count').textContent =
   304→        apps.filter(a => a.status === 'offered').length;
   305→    }
   306→
   307→    function renderApplications() {
   308→      const container = document.getElementById('applications-list');
   309→
   310→      let filtered = applications;
   311→      if (currentFilter !== 'all') {
   312→        filtered = filtered.filter(a => a.status === currentFilter);
   313→      }
   314→      if (currentJob) {
   315→        filtered = filtered.filter(a => a.job_id == currentJob);
   316→      }
   317→
   318→      if (filtered.length === 0) {
   319→        container.innerHTML = `
   320→          <div class="empty-state">
   321→            <p>No applications found</p>
   322→            <a href="/job-create.html" class="btn btn-primary btn-sm">Post a Job</a>
   323→          </div>
   324→        `;
   325→        return;
   326→      }
   327→
   328→      container.innerHTML = filtered.map(app => {
   329→        // Build screening answers display
   330→        let screeningHTML = '';
   331→        const answers = typeof app.screening_answers === 'string' ? JSON.parse(app.screening_answers || '{}') : (app.screening_answers || {});
   332→        const questions = typeof app.screening_questions === 'string' ? JSON.parse(app.screening_questions || '[]') : (app.screening_questions || []);
   333→
   334→        if (questions.length > 0 && Object.keys(answers).length > 0) {
   335→          screeningHTML = `
   336→            <div class="screening-answers">
   337→              <div class="screening-label">📋 Screening Answers</div>
   338→              <div class="screening-grid">
   339→                ${questions.map(q => {
   340→                  const ans = answers[q.id] || '-';
   341→                  return `<div class="screening-item">
   342→                    <span class="sq-q">${q.question}</span>
   343→                    <span class="sq-a ${q.type === 'yes_no' ? (ans === 'yes' ? 'sq-yes' : 'sq-no') : ''}">${ans}</span>
   344→                  </div>`;
   345→                }).join('')}
   346→              </div>
   347→            </div>`;
   348→        }
   349→
   350→        // Build candidate insights
   351→        let insightsHTML = '';
   352→        if (app.verified_skills_count > 0 || app.best_interview_score || app.completed_interviews > 0) {
   353→          insightsHTML = `<div class="candidate-insights">
   354→            ${app.verified_skills_count > 0 ? `<span class="insight-badge skill-badge">✓ ${app.verified_skills_count} Verified Skill${app.verified_skills_count > 1 ? 's' : ''}</span>` : ''}
   355→            ${app.best_interview_score ? `<span class="insight-badge interview-badge">🎤 Best Interview: ${app.best_interview_score}/10</span>` : ''}
   356→            ${app.completed_interviews > 0 ? `<span class="insight-badge practice-badge">📝 ${app.completed_interviews} Mock Interview${app.completed_interviews > 1 ? 's' : ''}</span>` : ''}
   357→          </div>`;
   358→        }
   359→
   360→        return `
   361→        <div class="application-card">
   362→          <div class="application-header">
   363→            <div class="candidate-info">
   364→              <div class="candidate-avatar">${(app.candidate_name || 'U').charAt(0).toUpperCase()}</div>
   365→              <div class="candidate-details">
   366→                <h3>${app.candidate_name || 'Unknown'}</h3>
   367→                <p>${app.job_title || 'Position'}</p>
   368→              </div>
   369→            </div>
   370→            <div class="application-meta">
   371→              ${app.omniscore_at_apply ? `<span class="omniscore-badge">${app.omniscore_at_apply} OmniScore</span>` : ''}
   372→              <span class="status-badge ${app.status}">${app.status}</span>
   373→            </div>
   374→          </div>
   375→          <div class="application-body">
   376→            <div class="application-info">
   377→              <span class="info-item">📧 ${app.candidate_email || 'No email'}</span>
   378→              <span class="info-item">📅 Applied ${formatDate(app.applied_at)}</span>
   379→              ${app.match_score ? `<span class="info-item">🎯 ${app.match_score}% Match</span>` : ''}
   380→            </div>
   381→            ${insightsHTML}
   382→            ${app.cover_letter ? `<p class="cover-letter-preview">${app.cover_letter.substring(0, 150)}...</p>` : ''}
   383→            ${screeningHTML}
   384→          </div>
   385→          <div class="application-actions">
   386→            <button onclick="updateStatus(${app.id}, 'reviewing')" class="btn btn-ghost btn-sm" ${app.status !== 'applied' ? 'disabled' : ''}>
   387→              Review
   388→            </button>
   389→            <button onclick="scheduleInterview(${app.id})" class="btn btn-ghost btn-sm">
   390→              Schedule Interview
   391→            </button>
   392→            <button onclick="makeOffer(${app.id}, ${app.candidate_id}, '${(app.candidate_name || '').replace(/'/g, "\\'")}', '${(app.candidate_email || '').replace(/'/g, "\\'")}', ${app.job_id}, '${(app.job_title || '').replace(/'/g, "\\'")}')" class="btn btn-primary btn-sm" ${app.status === 'offered' || app.status === 'hired' ? 'disabled' : ''}>
   393→              Make Offer
   394→            </button>
   395→            <button onclick="updateStatus(${app.id}, 'rejected')" class="btn btn-ghost btn-sm danger">
   396→              Reject
   397→            </button>
   398→          </div>
   399→        </div>

